"use client";

import { useState, useEffect, useMemo } from "react";
import { useAuth } from "@/context/AuthContext";
import { useRouter, useParams } from "next/navigation";
import PriceChart, { generatePriceHistory } from "@/components/PriceChart";
import { STOCKS, getSimulatedPrice, getHoldings, saveHoldings, getDailyChange } from "@/lib/assets";
import { ArrowLeft, X, CheckCircle2, Loader2 } from "lucide-react";

const TIME_RANGES = ["1D", "1W", "1M", "1Y", "ALL"];
const PRESET_AMOUNTS = [1, 10, 20, 50, 100];
const POINTS_MAP = { "1D": 96, "1W": 168, "1M": 30, "1Y": 365, "ALL": 500 };
const VOLATILITY_MAP = { "1D": 0.002, "1W": 0.005, "1M": 0.01, "1Y": 0.03, "ALL": 0.05 };

export default function StockDetailPage() {
    const { user, loading } = useAuth();
    const router = useRouter();
    const params = useParams();
    const symbol = params.symbol?.toUpperCase();

    const stock = STOCKS.find(s => s.symbol === symbol);

    const [timeRange, setTimeRange] = useState("1D");
    const [showBuy, setShowBuy] = useState(false);
    const [showSell, setShowSell] = useState(false);
    const [showConfirm, setShowConfirm] = useState(false);
    const [amount, setAmount] = useState("");
    const [isProcessing, setIsProcessing] = useState(false);
    const [success, setSuccess] = useState(false);
    const [orderType, setOrderType] = useState("buy");

    const price = useMemo(() => stock ? getSimulatedPrice(stock.basePrice) : 0, [stock]);
    const change = useMemo(() => stock ? getDailyChange(stock.symbol) : 0, [stock]);
    const isUp = change >= 0;

    const chartData = useMemo(() =>
        stock ? generatePriceHistory(price, VOLATILITY_MAP[timeRange], POINTS_MAP[timeRange]) : []
        , [timeRange, price, stock]);

    const holdings = user ? getHoldings(user.id) : {};
    const shareQty = holdings[symbol] || 0;
    const shareValue = shareQty * price;

    useEffect(() => {
        if (!loading && !user) router.push("/login");
    }, [user, loading]);

    if (!stock) {
        return (
            <div className="min-h-screen bg-white dark:bg-black flex items-center justify-center">
                <p className="text-gray-500">Stock not found</p>
            </div>
        );
    }

    const handleConfirm = () => {
        const amt = parseFloat(amount);
        if (!amt || amt <= 0) return;
        setIsProcessing(true);

        setTimeout(() => {
            const h = getHoldings(user.id);
            const shares = amt / price;

            if (orderType === "buy") {
                h[symbol] = (h[symbol] || 0) + shares;
            } else {
                h[symbol] = Math.max(0, (h[symbol] || 0) - shares);
            }

            saveHoldings(user.id, h);
            setIsProcessing(false);
            setSuccess(true);

            setTimeout(() => {
                setSuccess(false);
                setShowConfirm(false);
                setShowBuy(false);
                setShowSell(false);
                setAmount("");
            }, 1800);
        }, 1500);
    };

    const openBuy = () => { setOrderType("buy"); setAmount(""); setShowBuy(true); };
    const openSell = () => { setOrderType("sell"); setAmount(""); setShowSell(true); };
    const goToConfirm = () => {
        const amt = parseFloat(amount);
        if (amt && amt > 0) {
            setShowBuy(false);
            setShowSell(false);
            setShowConfirm(true);
        }
    };

    if (loading || !user) return null;

    const amt = parseFloat(amount) || 0;
    const shares = amt / price;

    return (
        <div className="min-h-screen bg-white dark:bg-black">
            {/* Header */}
            <div className="flex items-center justify-between p-6">
                <button onClick={() => router.back()} className="p-2 hover:bg-gray-100 dark:hover:bg-zinc-800 rounded-full transition-all">
                    <ArrowLeft className="w-6 h-6" />
                </button>
                <div className="w-10" />
            </div>

            {/* Asset Info */}
            <div className="px-6">
                <div className="flex items-center justify-between mb-2">
                    <div className="flex items-center space-x-4">
                        <div className="w-14 h-14 rounded-full flex items-center justify-center text-2xl shadow-sm border border-gray-100 dark:border-zinc-800" style={{ backgroundColor: stock.color + '15' }}>
                            {stock.icon}
                        </div>
                        <div>
                            <h1 className="text-2xl font-bold">{stock.name}</h1>
                            <p className={`text-sm font-bold ${isUp ? 'text-cashapp' : 'text-red-500'}`}>
                                {isUp ? '↑' : '↓'} {Math.abs(change).toFixed(2)}%
                            </p>
                        </div>
                    </div>
                    <div className="bg-gray-100 dark:bg-zinc-800 px-4 py-2 rounded-full">
                        <p className="text-lg font-bold">${price.toFixed(2)}</p>
                    </div>
                </div>

                {/* Holdings */}
                {shareQty > 0 && (
                    <div className="mt-4 p-4 bg-blue-50 dark:bg-blue-900/10 rounded-2xl border border-blue-200/30 dark:border-blue-700/20">
                        <p className="text-xs text-gray-500 font-bold uppercase tracking-widest">Your {stock.name}</p>
                        <p className="text-xl font-bold mt-1">{shareQty.toFixed(6)} shares</p>
                        <p className="text-sm text-gray-500">≈ ${shareValue.toFixed(2)}</p>
                    </div>
                )}
            </div>

            {/* Chart */}
            <div className="px-2 mt-6">
                <PriceChart data={chartData} color={stock.color} height={220} />
            </div>

            {/* Time Range Tabs */}
            <div className="flex justify-center space-x-2 px-6 mt-4 mb-8">
                {TIME_RANGES.map(t => (
                    <button
                        key={t}
                        onClick={() => setTimeRange(t)}
                        className={`px-4 py-2 rounded-full text-sm font-bold transition-all ${timeRange === t
                                ? 'bg-black dark:bg-white text-white dark:text-black'
                                : 'text-gray-400 hover:text-gray-600'
                            }`}
                    >
                        {t}
                    </button>
                ))}
            </div>

            {/* Buy / Sell Buttons */}
            <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto p-6 bg-white/80 dark:bg-black/80 backdrop-blur-md border-t border-gray-100 dark:border-zinc-800">
                <div className="flex space-x-3">
                    <button onClick={openBuy} className="flex-1 bg-black dark:bg-white text-white dark:text-black font-bold py-4 rounded-full text-lg hover:scale-[1.02] active:scale-95 transition-all">
                        Buy
                    </button>
                    <button onClick={openSell} className="flex-1 bg-gray-100 dark:bg-zinc-800 font-bold py-4 rounded-full text-lg hover:scale-[1.02] active:scale-95 transition-all">
                        Sell
                    </button>
                </div>
            </div>

            {/* Buy/Sell Sheet */}
            {(showBuy || showSell) && (
                <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/50" onClick={() => { setShowBuy(false); setShowSell(false); }}>
                    <div
                        className="w-full max-w-md bg-white dark:bg-zinc-900 rounded-t-3xl p-6 animate-in slide-in-from-bottom duration-300"
                        onClick={e => e.stopPropagation()}
                    >
                        <div className="flex justify-center mb-4">
                            <div className="w-12 h-1.5 bg-gray-200 dark:bg-zinc-700 rounded-full" />
                        </div>

                        <h2 className="text-xl font-bold text-center mb-2">
                            {orderType === "buy" ? "Buy" : "Sell"} {stock.name}
                        </h2>
                        <div className="flex justify-center mb-6">
                            <span className="px-4 py-1.5 bg-gray-100 dark:bg-zinc-800 rounded-full text-sm font-medium">
                                One-Time Purchase ▾
                            </span>
                        </div>

                        {/* Preset Amounts */}
                        <div className="grid grid-cols-3 gap-3 mb-6">
                            {PRESET_AMOUNTS.map(a => (
                                <button
                                    key={a}
                                    onClick={() => setAmount(String(a))}
                                    className={`py-4 rounded-2xl font-bold text-lg transition-all border ${amount === String(a)
                                            ? 'border-black dark:border-white bg-gray-50 dark:bg-zinc-800'
                                            : 'border-gray-200 dark:border-zinc-700 hover:border-gray-400'
                                        }`}
                                >
                                    ${a}
                                </button>
                            ))}
                            <button
                                onClick={() => {
                                    const custom = prompt("Enter custom amount ($):");
                                    if (custom && !isNaN(custom)) setAmount(custom);
                                }}
                                className={`py-4 rounded-2xl font-bold text-lg transition-all border ${amount && !PRESET_AMOUNTS.includes(Number(amount))
                                        ? 'border-black dark:border-white bg-gray-50 dark:bg-zinc-800'
                                        : 'border-gray-200 dark:border-zinc-700 hover:border-gray-400'
                                    }`}
                            >
                                {amount && !PRESET_AMOUNTS.includes(Number(amount)) ? `$${amount}` : '...'}
                            </button>
                        </div>

                        <button
                            onClick={goToConfirm}
                            disabled={!amount || parseFloat(amount) <= 0}
                            className="w-full bg-black dark:bg-white text-white dark:text-black font-bold py-4 rounded-full text-lg disabled:opacity-30 hover:scale-[1.02] active:scale-95 transition-all"
                        >
                            Next
                        </button>
                    </div>
                </div>
            )}

            {/* Confirm Sheet */}
            {showConfirm && (
                <div className="fixed inset-0 z-50 flex flex-col bg-white dark:bg-black">
                    <div className="flex justify-end p-6">
                        <button onClick={() => { setShowConfirm(false); setAmount(""); }} className="p-2 hover:bg-gray-100 dark:hover:bg-zinc-800 rounded-full transition-all">
                            <X className="w-6 h-6" />
                        </button>
                    </div>

                    {success ? (
                        <div className="flex-1 flex flex-col items-center justify-center">
                            <CheckCircle2 className="w-20 h-20 text-cashapp mb-4 animate-bounce" />
                            <h2 className="text-2xl font-bold">Order Placed!</h2>
                            <p className="text-gray-500 mt-2">
                                {orderType === "buy" ? "Bought" : "Sold"} ${amt.toFixed(2)} of {stock.name}
                            </p>
                        </div>
                    ) : (
                        <div className="flex-1 flex flex-col justify-between px-8 pb-8">
                            <div>
                                <h2 className="text-3xl font-bold mb-10">
                                    {orderType === "buy" ? "Buy" : "Sell"} ${amt.toFixed(2)} of {stock.name}
                                </h2>

                                <div className="space-y-4">
                                    {[
                                        { label: "Funding Source", value: "FlowCash" },
                                        { label: "Order Type", value: "Market" },
                                        { label: "Approx Share Price", value: `$${price.toFixed(2)}` },
                                        { label: "Approx Shares", value: shares.toFixed(6) },
                                        { label: "Symbol", value: symbol },
                                    ].map(row => (
                                        <div key={row.label} className="flex justify-between py-2">
                                            <span className="text-gray-500">{row.label}</span>
                                            <span className="font-bold">{row.value}</span>
                                        </div>
                                    ))}

                                    <div className="border-t border-gray-100 dark:border-zinc-800 pt-4 mt-4 space-y-3">
                                        <div className="flex justify-between">
                                            <span className="text-gray-500">Total Purchase Amount</span>
                                            <span className="font-bold">${amt.toFixed(2)}</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span className="text-gray-500">Fees</span>
                                            <span className="font-bold">$0.00</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span className="text-gray-500 font-bold">Total Cost</span>
                                            <span className="font-bold text-lg">${amt.toFixed(2)}</span>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <button
                                onClick={handleConfirm}
                                disabled={isProcessing}
                                className="w-full bg-black dark:bg-white text-white dark:text-black font-bold py-5 rounded-full text-lg hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-50"
                            >
                                {isProcessing ? <Loader2 className="w-6 h-6 animate-spin mx-auto" /> : "Confirm"}
                            </button>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}
